const express = require('express');
const app = express();
app.use(express.json());

const mongoose = require('mongoose');

// Connect to the database
mongoose.connect('mongodb://localhost/e-commerce', { useNewUrlParser: true, useUnifiedTopology: true });

// Define the database schema
const productSchema = new mongoose.Schema({
    name: String,
    description: String,
    price: Number,
    stock: Number,
    category: { type: mongoose.Schema.Types.ObjectId, ref: 'Category' },
    reviews: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Review' }]
});

const categorySchema = new mongoose.Schema({
    name: String,
    products: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Product' }]
});

const reviewSchema = new mongoose.Schema({
    productId: { type: mongoose.Schema.Types.ObjectId, ref: 'Product' },
    rating: Number,
    content: String
});

const orderSchema = new mongoose.Schema({
    customerId: { type: mongoose.Schema.Types.ObjectId, ref: 'Customer' },
    products: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Product' }],
    total: Number
});

const customerSchema = new mongoose.Schema({
    name: String,
    email: String,
    orders: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Order' }]
});

// Create the database models
const Product = mongoose.model('Product', productSchema);
const Category = mongoose.model('Category', categorySchema);
const Review = mongoose.model('Review', reviewSchema);
const Order = mongoose.model('Order', orderSchema);
const Customer = mongoose.model('Customer', customerSchema);

// Define the API endpoints
app.get('/api/products', async (req, res) => {
    // Retrieve a list of all products with their respective categories and reviews
    const products = await Product.find().populate('category', 'name').populate('reviews', 'rating content');
    res.json(products);
});

app.get('/api/products/:id', async (req, res) => {
    // Retrieve a specific product with its category and reviews
    const productId = req.params.id;
    const product = await Product.findById(productId).populate('category', 'name').populate('reviews', 'rating content');
    res.json(product);
});

app.post('/api/products', async (req, res) => {
    // Create a new product with a category and reviews
    const product = new Product(req.body);
    await product.save();
    res.json(product);
});

app.put('/api/products/:id', async (req, res) => {
    // Update a specific product with a category and reviews
    const productId = req.params.id;
    const product = await Product.findByIdAndUpdate(productId, req.body, { new: true });
    res.json(product);
});

app.delete('/api/products/:id', async (req, res) => {
    // Delete a specific product
    const productId = req.params.id;
    await Product.findByIdAndRemove(productId);
    res.json({ message: 'Product deleted successfully' });
});

app.get('/api/orders', async (req, res) => {
    // Retrieve a list of all orders with their respective customers and products
    const orders = await Order.find().populate('customerId', 'name email').populate('products', 'name price');
    res.json(orders);
});

app.post('/api/orders', async (req, res) => {
    // Create a new order with a customer and products
    const order = new Order(req.body);
    await order.save();
    res.json(order);
});

app.get('/api/orders/:id', async (req, res) => {
    // Retrieve a specific order with its customer and products
    const orderId = req.params.id;
    const order = await Order.findById(orderId).populate('customerId', 'name email').populate('products', 'name price');
    res.json(order);
});

app.put('/api/orders/:id', async (req, res) => {
    // Update a specific order with a customer and products
    const orderId = req.params.id;
    const order = await Order.findByIdAndUpdate(orderId, req.body, { new: true });
    res.json(order);
});

app.delete('/api/orders/:id', async (req, res) => {
    // Delete a specific order
    const orderId = req.params.id;
    await Order.findByIdAndRemove(orderId);
    res.json({ message: 'Order deleted successfully' });
});

app.get('/api/customers', async (req, res) => {
    // Retrieve a list of all customers with their respective orders
    const customers = await Customer.find().populate('orders', 'customerId name email products');
    res.json(customers);
});

app.post('/api/customers', async (req, res) => {
    // Create a new customer with orders
    const customer = new Customer(req.body);
    await customer.save();
    res.json(customer);
});

app.get('/api/customers/:id', async (req, res) => {
    // Retrieve a specific customer with their orders
    const customerId = req.params.id;
    const customer = await Customer.findById(customerId).populate('orders', 'customerId name email products');
    res.json(customer);
});

app.put('/api/customers/:id', async (req, res) => {
    // Update a specific customer with orders
    const customerId = req.params.id;
    const customer = await Customer.findByIdAndUpdate(customerId, req.body, { new: true });
    res.json(customer);
});

app.delete('/api/customers/:id', async (req, res) => {
    // Delete a specific customer
    const customerId = req.params.id;
    await Customer.findByIdAndRemove(customerId);
    res.json({ message: 'Customer deleted successfully' });
});

app.listen(process.env.PORT || 3000, () => {
    console.log('Server running on port ' + (process.env.PORT || 3000));
});
